import React, { Fragment, useState } from "react";
import {
  BrowserRouter as Router,
  Route,
  Routes,
  Navigate,
} from "react-router-dom";

import Home from "./routes/Home";
import Login from "./routes/Login";
import Registration from "./routes/Registration";
import ProductDetails from "./routes/ProductDetails"; // Import the ProductDetails component

const App = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const setAuth = (boolean) => {
    setIsAuthenticated(boolean);
  };
  
  return (
    <Fragment>
      <Router>
        <Routes>
          <Route
            path="/"
            element={isAuthenticated ? <Home setAuth={setAuth} /> : <Navigate to="/login" />}
          />
          <Route
            path="/login"
            element={!isAuthenticated ? <Login setAuth={setAuth} /> : <Navigate to="/" />}
          />
          <Route
            path="/registration"
            element={!isAuthenticated ? <Registration setAuth={setAuth} /> : <Navigate to="/" />}
          />
          <Route path="/product/:id" element={<ProductDetails />} /> {/* New route for ProductDetails */}
        </Routes>
      </Router>
    </Fragment>
  );
};

export default App;
